#include<bits/stdc++.h>
using namespace std;
long long f[3010],sum[3010],s[3010],a[3010][3010],n,m,top,ans;
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            scanf("%lld",&a[i][j]);
        }
    }
    for(long long i=1;i<=n;i++)
    {
        top=0;
        for(long long j=1;j<=m;j++)
        {
            if(a[i][j]==0)
            {
                f[j]=i;
            }
            while(top&&f[s[top]]<f[j])
            {
                top--;
            }
            s[++top]=j;
            sum[top]=sum[top-1]+(i-f[s[top]])*(s[top]-s[top-1]);
            ans+=sum[top];
        }
    }
    printf("%lld",ans);
    return 0;
}
